const t = $('Execute Sub-workflow Trigger').first().json;
const insert = $('Postgres: Insertar Gasto').first().json;
const chk = $input.first().json;
let out = `Gasto registrado correctamente con ID #${insert.id}. Monto: $${t.monto}, Categoría: ${t.categoria}`;
if (t.descripcion && t.descripcion !== 'null' && t.descripcion !== '') {
  out += `, Descripción: ${t.descripcion}`;
}
out += '.';
if (chk.monto_limite !== null && chk.monto_limite !== undefined) {
  const lim = Number(chk.monto_limite);
  const gastado = Number(chk.gastado);
  const pct = lim > 0 ? Math.round((gastado / lim) * 100) : 0;
  if (gastado > lim) {
    out += ` ⚠️ Superaste el presupuesto de ${t.categoria}: $${gastado} de $${lim} (${pct}%) este mes.`;
  } else if (pct >= 80) {
    out += ` ⚠️ Atención: llevás $${gastado} de $${lim} en ${t.categoria} este mes (${pct}%).`;
  }
}
return [{ json: { output: out } }];
